class Piece:
    def __init__(self, color, type):
        self.color = color
        self.type = type

    def get_type(self):
        return self.type


class Board:
    def __init__(self):
        self.cells = [[None] * 8 for _ in range(8)]
        self.setup_board()

    def setup_board(self):
        colors = ["B", "W"]
        for i in range(8):
            for j in range(3):
                if (i + j) % 2 == 1:
                    self.cells[i][j] = Piece(colors[0], "Regular")
            for j in range(5, 8):
                if (i + j) % 2 == 1:
                    self.cells[i][j] = Piece(colors[1], "Regular")

    def get_piece(self, row, col):
        return self.cells[row][col]

    def move_piece(self, start_row, start_col, end_row, end_col):
        piece = self.get_piece(start_row, start_col)
        self.cells[start_row][start_col] = None
        self.cells[end_row][end_col] = piece

    def capture_piece(self, row, col):
        self.cells[row][col] = None


class Player:
    def __init__(self, name):
        self.name = name
        self.pieces = []

    def has_pieces(self):
        return len(self.pieces) > 0

    def king_piece(self, piece):
        if piece.type == "Regular":
            piece.type = "King"


class Game:
    def __init__(self):
        self.board = Board()
        self.players = [Player("White"), Player("Black")]
        self.current_turn = 0

    def get_turn(self):
        return self.players[self.current_turn % 2].name

    def make_move(self, start_pos, end_pos):
        piece = self.board.get_piece(start_pos[0], start_pos[1])
        if piece:
            self.board.move_piece(start_pos[0], start_pos[1], end_pos[0], end_pos[1])

    def check_win_conditions(self):
        current_player = self.players[self.current_turn % 2]
        opponent_player = self.players[(self.current_turn + 1) % 2]
        if not current_player.has_pieces():
            return f"{opponent_player.name} wins!"
        return None


if __name__ == "__main__":
    game = Game()
    print(f"Current turn: {game.get_turn()}")
